-- Table: vehicles
DROP TABLE IF EXISTS `vehicles`;
CREATE TABLE `vehicles` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) NOT NULL,
  `category` enum('berline','suv','4x4','pickup','luxe','minibus','mariage','economique') NOT NULL,
  `type` enum('location','vente') NOT NULL DEFAULT 'location',
  `price_without_driver` int(11) NOT NULL,
  `price_with_driver` int(11) NOT NULL,
  `sale_price` int(11) DEFAULT NULL,
  `year` int(11) DEFAULT NULL,
  `mileage` varchar(50) DEFAULT NULL,
  `fuel_type` varchar(50) DEFAULT NULL,
  `transmission` varchar(50) DEFAULT NULL,
  `features` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`features`)),
  `description` text DEFAULT NULL,
  `image_url` varchar(255) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `dest_abidjan` tinyint(1) DEFAULT 1,
  `dest_interieur` tinyint(1) DEFAULT 1,
  `stock` int(11) DEFAULT 3,
  `stock_alert_threshold` int(11) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `images` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`images`)),
  `autorise_sans_chauffeur_abidjan` tinyint(1) NOT NULL DEFAULT 1,
  `autorise_sans_chauffeur_hors_abidjan` tinyint(1) NOT NULL DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `idx_vehicles_category` (`category`),
  KEY `idx_vehicles_active` (`is_active`),
  KEY `idx_vehicles_stock` (`stock`)
) ENGINE=InnoDB AUTO_INCREMENT=221 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

