-- Table: reservations
DROP TABLE IF EXISTS `reservations`;
CREATE TABLE `reservations` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `client_name` varchar(100) NOT NULL,
  `client_whatsapp` varchar(20) NOT NULL,
  `vehicle_id` int(11) DEFAULT NULL,
  `start_date` date NOT NULL,
  `start_time` time NOT NULL,
  `end_date` date NOT NULL,
  `end_time` time NOT NULL,
  `pickup_location` varchar(255) NOT NULL,
  `with_driver` tinyint(1) DEFAULT 0,
  `quantity` int(11) DEFAULT 1,
  `total_price` int(11) NOT NULL,
  `message` text DEFAULT NULL,
  `promo_code` varchar(20) DEFAULT NULL,
  `discount_amount` int(11) DEFAULT 0,
  `status` enum('pending','confirmed','completed','cancelled') DEFAULT 'pending',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_reservations_dates` (`start_date`,`end_date`),
  KEY `idx_reservations_status` (`status`),
  KEY `idx_reservations_whatsapp` (`client_whatsapp`),
  KEY `reservations_ibfk_1` (`vehicle_id`),
  CONSTRAINT `reservations_ibfk_1` FOREIGN KEY (`vehicle_id`) REFERENCES `vehicles` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=61 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

